/**
 * MedX fonts theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Font family stacks and fallbacks.
 */
const FONTS_TOKENS = Object.freeze({
  primary: { value: "theme-fonts-primary", scope: "theme" },
  secondary: { value: "theme-fonts-secondary", scope: "theme" },
  muted: { value: "theme-fonts-muted", scope: "theme" },
  accent: { value: "theme-fonts-accent", scope: "theme" },
  surface: { value: "theme-fonts-surface", scope: "theme" },
});

const FONTS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const FONTS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const fontsRegistry = new Map();
const FONTS_listeners = new Set();
let FONTS_seq = 0;

function createFontsId(prefix = "medx-theme-fonts") {
  FONTS_seq += 1;
  return `${prefix}-${FONTS_seq}`;
}

function registerFonts(config = {}) {
  const entryId = config.id ?? createFontsId();
  const preset = FONTS_PRESETS[config.preset ?? "default"] ?? FONTS_PRESETS.default;
  const token = FONTS_TOKENS[config.token ?? preset.token] ?? FONTS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: FONTS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  fontsRegistry.set(entryId, entry);
  notifyFontsListeners("register", entry);
  return entry;
}

function updateFonts(id, patch = {}) {
  const entry = fontsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyFontsListeners("update", entry);
  return entry;
}

function resolveFonts(id) {
  const entry = fontsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listFontsEntries(filter = {}) {
  let items = Array.from(fontsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onFontsEvent(listener) {
  FONTS_listeners.add(listener);
  return () => FONTS_listeners.delete(listener);
}

function notifyFontsListeners(type, entry) {
  for (const listener of FONTS_listeners) {
    try {
      listener({ type, entry, registrySize: fontsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:fonts] listener error", err.message);
    }
  }
}

function getFontsMetrics() {
  const items = listFontsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(FONTS_TOKENS).length,
    presets: Object.keys(FONTS_PRESETS).length,
  };
}

async function runMedxFonts() {
  console.log("[medx:ui:theme:fonts] runtime initialized");
  console.log(`[medx:ui:theme:fonts] tokens=${Object.keys(FONTS_TOKENS).length} presets=${Object.keys(FONTS_PRESETS).length}`);

  const events = [];
  onFontsEvent((e) => events.push(e.type));

  const domains = Object.keys(FONTS_SUPPLY_CHAIN);
  const presets = Object.keys(FONTS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerFonts({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/fonts" },
    });
  }

  const first = listFontsEntries()[0];
  if (first) updateFonts(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getFontsMetrics();
  const resolved = first ? resolveFonts(first.id) : null;

  console.log(`[medx:ui:theme:fonts] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:fonts] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:fonts] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:fonts] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:fonts] bootstrap complete");
}

module.exports = runMedxFonts;
